CREATE TABLE IF NOT EXISTS valora.forms (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NULL REFERENCES valora.organizations(id), name text NOT NULL, description text, category text, time_min int, scoring_method text, status text NOT NULL DEFAULT 'draft', is_global boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), is_deleted boolean NOT NULL DEFAULT false);
CREATE TABLE IF NOT EXISTS valora.form_dimensions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), form_id uuid NOT NULL REFERENCES valora.forms(id), name text NOT NULL, description text, display_order int NOT NULL DEFAULT 0, max_score numeric(10,2));
CREATE TABLE IF NOT EXISTS valora.questions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), form_id uuid NOT NULL REFERENCES valora.forms(id), dimension_id uuid NULL REFERENCES valora.form_dimensions(id), text text NOT NULL, help text, type text NOT NULL, weight numeric(10,2) NOT NULL DEFAULT 1, max_score numeric(10,2), required boolean NOT NULL DEFAULT true, display_order int NOT NULL DEFAULT 0, settings_json jsonb NOT NULL DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS valora.question_options (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), question_id uuid NOT NULL REFERENCES valora.questions(id), text text NOT NULL, score numeric(10,2), is_correct boolean, display_order int NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS valora.surveys (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES valora.organizations(id), form_id uuid NOT NULL REFERENCES valora.forms(id), title text NOT NULL, description text, status text NOT NULL DEFAULT 'draft', token_hash text NOT NULL UNIQUE, public_slug text UNIQUE, public_url text, starts_at timestamptz, expires_at timestamptz, is_free boolean NOT NULL DEFAULT false, is_featured boolean NOT NULL DEFAULT false, visible_on_home boolean NOT NULL DEFAULT false, allow_repeat boolean NOT NULL DEFAULT false, require_identification boolean NOT NULL DEFAULT true, lgpd_required boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), is_deleted boolean NOT NULL DEFAULT false);
